from collections import deque

flowers = input()

queue = deque()

for index, flower in enumerate(flowers):
    if flower == '.':
        continue
    queue.append((flower, index))

def can_blend(flowers, queue):
    if 'A' in flowers and 'B' in flowers and 'C' in flowers:
        return True

    if not queue:
        return False

    flowers_1, index_1 = queue.popleft()
    if flowers_1 == 'A':
        flowers_2 = 'B'
    elif flowers_1 == 'B':
        flowers_2 = 'C'
    else:
        flowers_2 = 'A'

    if index_1 != 0 and flowers[index_1 - 1] != '.' and flowers_2 != flowers[index_1 - 1]:
        queue.append((flowers_1, index_1))
        return can_blend(flowers, queue)
    if index_1 != len(flowers) - 1 and flowers[index_1 + 1] != '.' and flowers_2 != flowers[index_1 + 1]:
        queue.append((flowers_1, index_1))
        return can_blend(flowers, queue)

    flowers = flowers[:index_1] + flowers_2 + flowers[index_1 + 1:]
    return can_blend(flowers, queue)

print('Yes' if can_blend(flowers, queue) else 'No')
